--
-- Core idea: outliers are modeled as uncertain directly; no separate “true value” resolution step.
--
-- Outlier flagging: IQR (precomputed; each row is labeled explicitly)
--   Nominal Score band: [70, 118]
--   is_outlier=TRUE  → Score={[0,101)} (uncertain; true value unknown)
--   is_outlier=FALSE → Score={[val,val+1)} (certain singleton interval)
--   is_outlier=NULL  → Score={[0,101)} (missing; uncertain)
--
-- Row counts: 720 normal + 68 outliers + 184 missing
-- Outlier rate: 7.0%
-- ================================================================
 
DROP TABLE IF EXISTS hospital_outlier_rset;
CREATE TABLE hospital_outlier_rset (
    ProviderNumber  INT,
    HospitalName    TEXT,
    ZipCode         int4range[],
    Score           int4range[],  -- normal rows: singleton interval; outliers: [0,101) uncertain
    u_r             INT,
    is_outlier      BOOLEAN       -- TRUE=outlier, FALSE=normal, NULL=missing
);
 
